import{_ as e,o,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Documents & Compliance","description":"","frontmatter":{},"headers":[],"relativePath":"modules/documents.md","filePath":"modules/documents.md"}'),a={name:"modules/documents.md"};function i(d,t,l,s,c,m){return o(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="documents-compliance" tabindex="-1">Documents &amp; Compliance <a class="header-anchor" href="#documents-compliance" aria-label="Permalink to &quot;Documents &amp; Compliance&quot;">​</a></h1><p>The Documents module provides a centralised repository for all company and employee documents. It covers policy publishing, contract storage, compliance document distribution with acknowledgement tracking, and personal employee file management.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Documents</strong> or <code>/documents</code>. The module is split into two tracks:</p><table tabindex="0"><thead><tr><th>Track</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Company Documents</strong></td><td><code>/documents/company</code></td><td>Policies, procedures, SOPs, templates</td></tr><tr><td><strong>Employee Documents</strong></td><td><code>/documents/employee</code></td><td>Personal files tied to individual employees</td></tr></tbody></table><hr><h2 id="company-documents" tabindex="-1">Company Documents <a class="header-anchor" href="#company-documents" aria-label="Permalink to &quot;Company Documents&quot;">​</a></h2><p>Company documents are files that apply to the organisation as a whole or to defined groups of employees. Examples include:</p><ul><li>Employee Handbook</li><li>Code of Conduct</li><li>GDPR / Privacy Policy</li><li>Health &amp; Safety Manual</li><li>IT Acceptable Use Policy</li><li>Standard Operating Procedures (SOPs)</li><li>Employment Contract Templates</li></ul><h3 id="uploading-a-company-document" tabindex="-1">Uploading a Company Document <a class="header-anchor" href="#uploading-a-company-document" aria-label="Permalink to &quot;Uploading a Company Document&quot;">​</a></h3><ol><li>Navigate to <strong>Documents → Company</strong></li><li>Click <strong>Upload Document</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Document Title</strong></td><td>Yes</td><td>Full descriptive name</td></tr><tr><td><strong>Category</strong></td><td>Yes</td><td>Policy / Contract / SOP / Handbook / Template / Other</td></tr><tr><td><strong>File</strong></td><td>Yes</td><td>PDF, DOCX, XLSX, PNG (max 20 MB)</td></tr><tr><td><strong>Version</strong></td><td>No</td><td>Version number (e.g., <code>v2.1</code>)</td></tr><tr><td><strong>Effective Date</strong></td><td>No</td><td>When this document comes into effect</td></tr><tr><td><strong>Expiry Date</strong></td><td>No</td><td>When this version expires (triggers a reminder)</td></tr><tr><td><strong>Visibility</strong></td><td>Yes</td><td>All Employees / Specific Departments / Admin Only</td></tr><tr><td><strong>Requires Acknowledgement</strong></td><td>No</td><td>If enabled, employees must confirm they have read it</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Brief summary of the document&#39;s purpose</td></tr></tbody></table><ol start="4"><li>Click <strong>Upload</strong></li></ol><h3 id="document-categories" tabindex="-1">Document Categories <a class="header-anchor" href="#document-categories" aria-label="Permalink to &quot;Document Categories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Policy</strong></td><td>Leave Policy, Expense Policy, Remote Work Policy</td></tr><tr><td><strong>Contract</strong></td><td>Employment Agreement Template, NDA Template</td></tr><tr><td><strong>SOP</strong></td><td>Onboarding Process, Performance Review Process</td></tr><tr><td><strong>Handbook</strong></td><td>Employee Handbook, Manager&#39;s Guide</td></tr><tr><td><strong>Template</strong></td><td>Offer Letter Template, Warning Letter Template</td></tr><tr><td><strong>Certificate</strong></td><td>ISO Certification, Business License</td></tr><tr><td><strong>Other</strong></td><td>Miscellaneous documents</td></tr></tbody></table><hr><h2 id="document-acknowledgement-tracking" tabindex="-1">Document Acknowledgement Tracking <a class="header-anchor" href="#document-acknowledgement-tracking" aria-label="Permalink to &quot;Document Acknowledgement Tracking&quot;">​</a></h2><p>When <strong>Requires Acknowledgement</strong> is enabled for a document, each employee who has visibility of the document must confirm they have read and understood it.</p><h3 id="how-acknowledgement-works" tabindex="-1">How Acknowledgement Works <a class="header-anchor" href="#how-acknowledgement-works" aria-label="Permalink to &quot;How Acknowledgement Works&quot;">​</a></h3><ol><li>After uploading the document with acknowledgement required, HR selects the <strong>target employees</strong> or departments</li><li>Each targeted employee receives an email notification with a link to the document</li><li>The employee: <ul><li>Logs in</li><li>Navigates to <strong>My Documents → Pending Acknowledgements</strong></li><li>Reads the document</li><li>Clicks <strong>I Acknowledge</strong> and optionally adds a comment</li></ul></li><li>The acknowledgement is recorded with timestamp and the employee&#39;s IP address</li></ol><h3 id="tracking-acknowledgement-status" tabindex="-1">Tracking Acknowledgement Status <a class="header-anchor" href="#tracking-acknowledgement-status" aria-label="Permalink to &quot;Tracking Acknowledgement Status&quot;">​</a></h3><p>HR can view the acknowledgement progress at any time:</p><ol><li>Open the company document</li><li>Click the <strong>Acknowledgements</strong> tab</li><li>The table shows:</li></ol><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Employee</td><td>Name and department</td></tr><tr><td>Status</td><td>Pending / Acknowledged</td></tr><tr><td>Acknowledged At</td><td>Date and time of acknowledgement</td></tr><tr><td>Comment</td><td>Optional employee comment</td></tr></tbody></table><ol start="4"><li>Filter by status to see who is still pending</li><li>Click <strong>Send Reminder</strong> to email pending employees</li></ol><h3 id="exporting-acknowledgement-records" tabindex="-1">Exporting Acknowledgement Records <a class="header-anchor" href="#exporting-acknowledgement-records" aria-label="Permalink to &quot;Exporting Acknowledgement Records&quot;">​</a></h3><p>Click <strong>Export CSV</strong> on the Acknowledgements tab to download the complete record for compliance audit purposes.</p><hr><h2 id="employee-documents" tabindex="-1">Employee Documents <a class="header-anchor" href="#employee-documents" aria-label="Permalink to &quot;Employee Documents&quot;">​</a></h2><p>Employee documents are personal files stored against individual employee records — contracts, ID proofs, academic certificates, background check results, etc.</p><h3 id="viewing-employee-documents" tabindex="-1">Viewing Employee Documents <a class="header-anchor" href="#viewing-employee-documents" aria-label="Permalink to &quot;Viewing Employee Documents&quot;">​</a></h3><p>From any employee&#39;s profile, click the <strong>Documents</strong> tab. All files associated with that employee are listed here.</p><h3 id="uploading-an-employee-document" tabindex="-1">Uploading an Employee Document <a class="header-anchor" href="#uploading-an-employee-document" aria-label="Permalink to &quot;Uploading an Employee Document&quot;">​</a></h3><p>HR staff can upload documents to any employee&#39;s record:</p><ol><li>Open the employee profile</li><li>Click the <strong>Documents</strong> tab</li><li>Click <strong>Upload Document</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Document Title</strong></td><td>Yes</td><td>Descriptive label</td></tr><tr><td><strong>Category</strong></td><td>Yes</td><td>Contract / ID Proof / Certificate / Medical / Other</td></tr><tr><td><strong>File</strong></td><td>Yes</td><td>PDF, JPG, PNG, DOCX (max 10 MB)</td></tr><tr><td><strong>Expiry Date</strong></td><td>No</td><td>For time-sensitive documents (passport, visa)</td></tr><tr><td><strong>Notes</strong></td><td>No</td><td>Internal notes</td></tr></tbody></table><ol start="5"><li>Click <strong>Upload</strong></li></ol><h3 id="employee-self-upload" tabindex="-1">Employee Self-Upload <a class="header-anchor" href="#employee-self-upload" aria-label="Permalink to &quot;Employee Self-Upload&quot;">​</a></h3><p>Employees can upload their own documents via <strong>My Profile → My Documents → Upload</strong>. HR must approve the upload before it is visible to other staff.</p><h3 id="document-categories-for-employee-files" tabindex="-1">Document Categories for Employee Files <a class="header-anchor" href="#document-categories-for-employee-files" aria-label="Permalink to &quot;Document Categories for Employee Files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Contract</strong></td><td>Signed employment contract, amendments</td></tr><tr><td><strong>ID Proof</strong></td><td>Passport copy, national ID, driving licence</td></tr><tr><td><strong>Certificate</strong></td><td>Degree certificates, professional certifications</td></tr><tr><td><strong>Medical</strong></td><td>Medical examination reports (stored securely)</td></tr><tr><td><strong>Warning Letter</strong></td><td>Formal warnings on record</td></tr><tr><td><strong>Performance Review</strong></td><td>Signed appraisal forms</td></tr><tr><td><strong>Tax Document</strong></td><td>Tax forms, declarations</td></tr><tr><td><strong>Other</strong></td><td>Any miscellaneous employee file</td></tr></tbody></table><hr><h2 id="document-expiry-reminders" tabindex="-1">Document Expiry Reminders <a class="header-anchor" href="#document-expiry-reminders" aria-label="Permalink to &quot;Document Expiry Reminders&quot;">​</a></h2><p>For documents with an <strong>Expiry Date</strong> set, GeniusHRM sends automatic reminder emails:</p><ul><li><strong>30 days</strong> before expiry: HR and the employee are notified</li><li><strong>7 days</strong> before expiry: Second reminder</li><li><strong>On expiry date</strong>: Final alert</li></ul><p>This is particularly useful for:</p><ul><li>Work visas and permits</li><li>Professional certifications requiring renewal</li><li>Periodic medical check-ups</li></ul><p>Configure reminder timing in <strong>Settings → Documents → Expiry Reminder Days</strong>.</p><hr><h2 id="downloading-documents" tabindex="-1">Downloading Documents <a class="header-anchor" href="#downloading-documents" aria-label="Permalink to &quot;Downloading Documents&quot;">​</a></h2><p>Any authorised user can download documents they have access to:</p><ul><li>Click <strong>Download</strong> next to any document in the list</li><li>The file downloads directly to the browser</li></ul><p>Documents are stored in <code>storage/app/private/documents/</code> and are served through Laravel&#39;s secure file controller — they are not publicly accessible via direct URL.</p><div class="warning custom-block"><p class="custom-block-title">Security</p><p>Employee documents containing personally identifiable information (PII) are served through authenticated routes only. Direct URL guessing is not possible. For GDPR compliance, restrict access to employee documents to HR staff and the employee themselves.</p></div><hr><h2 id="bulk-document-distribution" tabindex="-1">Bulk Document Distribution <a class="header-anchor" href="#bulk-document-distribution" aria-label="Permalink to &quot;Bulk Document Distribution&quot;">​</a></h2><p>To distribute a document to many employees at once:</p><ol><li>Upload the company document</li><li>Set <strong>Visibility</strong> to <code>All Employees</code> or select specific departments</li><li>Enable <strong>Requires Acknowledgement</strong> if needed</li><li>The document is immediately visible to all targeted employees in their <strong>My Documents</strong> portal</li></ol><p>For a targeted distribution to a custom list of employees:</p><ol><li>Upload the document with Visibility = <code>Admin Only</code></li><li>Open the document</li><li>Click <strong>Assign to Employees</strong></li><li>Search and select individual employees</li><li>Click <strong>Assign</strong></li></ol>',61)])])}const u=e(a,[["render",i]]);export{g as __pageData,u as default};
